import anthropic
import traceback

client = anthropic.Anthropic()

def execute_tool(tool_name: str, tool_input: dict) -> dict:
    """
    Dispatcher: maps tool names to implementation functions.
    Always returns a dict, never raises.
    """
    try:
        if tool_name == "search_knowledge_base":
            return search_knowledge_base(**tool_input)
        elif tool_name == "create_ticket":
            return create_ticket(**tool_input)
        else:
            return {"error": f"Unknown tool: {tool_name}", "error_code": "UNKNOWN_TOOL"}
    except ValueError as e:
        return {"error": f"Invalid input: {e}", "error_code": "INVALID_INPUT"}
    except PermissionError as e:
        return {"error": f"Permission denied: {e}", "error_code": "PERMISSION_DENIED"}
    except Exception as e:
        # Log the full traceback internally, return safe message to model
        traceback.print_exc()
        return {"error": "Internal error. Please try again.", "error_code": "INTERNAL_ERROR"}

def run_agent_loop(user_message: str, tools: list, system: str) -> str:
    """Complete agentic loop with tool handling."""
    messages = [{"role": "user", "content": user_message}]

    while True:
        response = client.messages.create(
            model="claude-opus-4-5",
            max_tokens=4096,
            system=system,
            tools=tools,
            messages=messages
        )

        # Add assistant response to history
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Find the last text block
            for block in reversed(response.content):
                if block.type == "text":
                    return block.text
            return ""

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = execute_tool(block.name, block.input)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": str(result)
                    })

            messages.append({"role": "user", "content": tool_results})
        else:
            break  # unexpected stop reason

    return ""
